<section data-for="panel-completions" class="d-flex-column flex-grow-1 h-100 of-auto">             
   <div data-plgn="tabs-content" class="d-flex-column flex-grow-1 of-auto">
      <div data-tab="chat" class="d-flex-column flex-grow-1">
         <h3 class="mgn-0">Chat <span data-fill="title"></span></h3>
         <section data-for="messages" data-flowdir="reverse" class="d-flex-column-rev flex-grow-1">
            
         </section>
         <section data-for="prompt-tools">
            
         </section>
         <textarea data-for="prompt-user" class="mgnb-0-25" style="height: 4rem;" 
            title="Shift+Enter to submit"></textarea>
      </div>
      <div data-tab="config" class="flex-grow-1 visibility-collapse">
         <h3 class="mgn-0">Prompt Details</h3>
         <label>System Prompt:</label>
         <textarea data-for="prompt-system" style="height: 20rem;"></textarea>
         <div>
            <label>Temp: </label>
            <input type="number" data-for="temp" value="0.4"/>
         </div>
         <div class="d-flex" style="align-items: center;">
            <label style="margin-right: 0.25rem">Chat mode: </label>
            <input type="checkbox" data-for="modeChat" checked/>
         </div>
         <div class="d-flex" style="align-items: center;">
            <label style="margin-right: 0.25rem">Markdown mode: </label>
            <input type="checkbox" data-for="modeMarkdown" />
         </div>
         <div>
            <button data-fn="clear-responses">Clear Responses</button>
         </div>
      </div>
   </div> <!-- end of tabs-content -->
   <div data-plgn="tabs">
      <div class="tab active" data-target="chat">Chat</div>
      <div class="tab" data-target="config">Config</div>
   </div> <!-- end of tabs -->         
</section>
